# CURRENT HYPOTHESIS: Summer x warm SST (threshold) x high chlorophyll (threshold)
def compute_risk(data: dict) -> float:
    summer = data.get('is_summer') or 0
    sst_anom = data.get('sst_anom') or 0
    chl_anom = data.get('chlorophyll_anom') or 0
    if summer < 0.5:
        return 0.0
    # Threshold approach: count how many conditions are met
    score = 0.3  # base summer risk
    if sst_anom > 0:
        score += 0.2  # warm anomaly
    if sst_anom > 0.5:
        score += 0.15  # very warm
    if chl_anom > 0:
        score += 0.2  # high chlorophyll
    if chl_anom > 0.3:
        score += 0.15  # very high chlorophyll
    return score
